var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그들이야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼らだからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that these employees whom you'd been giving a lot of thought were absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他們是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그들과 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼らとともにいることを。","ENG":"that you'll be with them, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他們一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called them to your office. They said they'd be here soon.","TWN":"做好心理準備後，你將他們傳喚到老闆辦公室，他們說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"안녕하시오, 종자여! 날 불렀다고 들었네!","JPN":"こんにちは、従者よ！　私を呼んだと聞いた！","ENG":"Hello, Squire! I heard you wanted to see me!","TWN":"哈囉手下！聽說你找我？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"…우으. 이 다음은 무슨 말을 해야…","JPN":"……うう。この後は何を話せば……","ENG":"...Ooh. What should I say next...?","TWN":"…呃，現在要說什麼…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"로빈, 관리자는 내가 아닌 널 호출한 거다.","JPN":"ロビン、管理者は私ではなく君を呼び出したのだ。","ENG":"Robin, the Administrator called for you, not me.","TWN":"蘿蘋，管理者是找你，不是找我。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"그렇게 내 뒤에 숨어서 대화하려는 시도는 바람직하지 않아.","JPN":"そうやって私の後ろに隠れて会話しようとするのは望ましくないな。","ENG":"It is inappropriate to speak to him while using me as a shield.","TWN":"你這樣躲在我背後說話不太好。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"아… 알겠습니다.","JPN":"わ……わかりました。","ENG":"Oh... Okay.","TWN":"嗯…好的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"음… 종자님. 그러니까…","JPN":"うーん……従者様。だから……","ENG":"Um... Squire? So...","TWN":"呃…手下，那個…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"아, 지난 번에 보내주신 명절 선물은 잘 먹었어요.","JPN":"あ、この前送ってくださったお歳暮、ご馳走様でした。","ENG":"Oh, thank you for the holiday gift you sent me last time.","TWN":"喔，上次過節你寄來的禮物我有收到，很好吃喔！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"특히 참치 통조림이 무척 맛있었습니다. 보너스로 챙겨 주신 떡도 달콤했어요.","JPN":"特にツナ缶がとても美味しかったです。ボーナスとしてくださったお餅も甘かったです。","ENG":"The canned tuna was really good. And the rice cake was sweet as well.","TWN":"特別是罐頭鮪魚真的好好吃，額外附的年糕也很美味。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"꼬박꼬박 들어오는 월급 덕에 맛집을 찾아 돌아다니는 게 요즘 낙이라 너무 즐거워…","JPN":"きちんと入ってくるお給料のおかげで美味しい飲食店を探しまわるのが最近の趣味でとても楽しい……","ENG":"I'm so pleased that I can go on a food tour in my free time, thanks to my steady income.","TWN":"現在每個月都有穩定的薪水入帳，所以我都會到處尋找美食，超快樂的…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"네? 고민이 있어 보이는 표정? 그렇게 티가 났나요?","JPN":"はい？　悩みがありそうな表情？　そんな顔に出てますか？","ENG":"Huh? Do I have something on my mind? Is it that obvious?","TWN":"嗯？我的臉看起來好像有什麼煩惱嗎？有這麼明顯喔？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"으음… 사실 이런 얘긴 다른 분에게 해본 적 없었는데.","JPN":"うーん……実はこういう話は他の人にしたことがなかったんですが。","ENG":"Um... To be honest, I've never talked about this with anyone before.","TWN":"嗯…這件事我從來沒跟別人提過。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"저, 맛있는 걸 보면 참지 못하는 성격이라서요. 모험을 하던 시절엔 아무리 맛있는 걸 많이 먹어도 괜찮았달까…","JPN":"私は、美味しいものを見ると我慢ができない性格なので。冒険をしていた頃はいくら美味しいものをたくさん食べても大丈夫だったというか……","ENG":"You see, I can't resist when I see something that looks delicious. It was okay to eat a lot when I was traveling the world...","TWN":"那個，我就是個看到好吃的東西就忍不住的吃貨。以前有在冒險時，不管吃多少東西都沒關係…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"그런데 요즘은 날이 갈수록 군살이 붙고 있어요.","JPN":"ですが最近は日に日に贅肉がついてきます。","ENG":"But these days, I feel like I'm gaining a little bit of weight.","TWN":"但最近，身體好像每天都在長胖。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"…맞아요. 욕망대로 맛있는 걸 마음껏 먹는 게 나쁜 건 아니죠.","JPN":"……そうです。欲望のまま美味しいものを思う存分食べるのは悪いことではないですよね。","ENG":"...You're right. It's not bad to eat tasty dishes to my heart's content.","TWN":"…是沒錯，能吃就是福。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"하지만 얼마 전, 오러 선생님께서 <color=#ffd34c>전보다 볼살이 커졌구나, 로빈.</color>이라고 말씀하셨을 때 뭔가 잘못됐단 걸 느꼈어요.","JPN":"でもこの前、オーラ先生が<color=#ffd34c>前より頬がぽっちゃりしたな、ロビン。</color>っておっしゃった時になにか間違いを犯していることに気付いたんです。","ENG":"But recently, Miss Aura said, <color=#ffd34c>\\"Your cheeks have gotten chubbier, Robin.\\"</color> And that's when I realized something was wrong.","TWN":"可是前幾天，奧蘿師父跟我說，<color=#ffd34c>蘿蘋，你的臉似乎越來越有肉</color>。我聽完就覺得不太對。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"욕망이 이끄는 대로 살다간 저…! 오러 선생님이 머리에 안 맞게 될지도 몰라요! 그럼 정말 큰일이잖아요.","JPN":"欲望に導かれるままに生きていては……！　オーラ先生が頭のサイズに合わなくなるかもしれません！　そうなったら本当に大変です！","ENG":"If I keep giving in to my desires...! My head might not fit Ms. Aura! Then, it'll really be a disaster.","TWN":"要是繼續這樣放任食慾，那我…！可能會胖到戴不下師父的頭盔！那真的會完蛋欸！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"아무래도 괜찮지 않냐고요?","JPN":"どうにかなるんじゃないかって？","ENG":"Isn't it okay?","TWN":"就算如此也無所謂？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"오러 선생님이 없는 저라도 충분히 믿고 맡길 수 있다니… 어째서 그런 부담되는 말씀을…","JPN":"オーラ先生がいない私も十分に信じて任せられるだなんて……どうしてそんなプレッシャーになるような言葉を……","ENG":"What do you mean, you'd put your trust in me, even without Ms. Aura...? Why would you say something so burdensome...?","TWN":"就算沒有師父你也如此信任我…說這種話是要逼哭我…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"역시 안되겠어요.","JPN":"やっぱりダメです。","ENG":"I can't.","TWN":"這樣不行。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"오늘부터 다이어트를 위한 일일 달리기 십만 보를 시작하겠습니다.","JPN":"今日からダイエットのために毎日ジョギング10万歩から始めます。","ENG":"Starting today, I'm going on a diet and walking 100,000 steps daily!","TWN":"從今天開始我要努力減肥，每天跑步十萬步！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"아뇨. 이번엔 오러 선생님 때문이 아니에요.","JPN":"いえ。むしろ今回は先生のせいではありません。","ENG":"No. It's not because of Ms. Aura this time.","TWN":"不，不是因為師父說的那些話。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"저 같은 사람을 신경 써 주시는 종자님에게… 좀 더 잘 보이고 싶으니까요.","JPN":"私のような者を気にかけてくださる従者様に……もっとよい姿を見せたいからです。","ENG":"I just want to impress you... because you actually care about me.","TWN":"是因為你這麼關心我…所以我想要展現更好的自己。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"물론 오러 선생님을 대신하는 건 쉽지 않겠지만…","JPN":"もちろんオーラ先生の代わりをするのは簡単ではないでしょうけど……","ENG":"I know that it won't be easy to fill Ms. Aura's shoes, but..","TWN":"當然，要取代師父並不容易…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"저도 한 사람의 기사로서, 종자님에게 보탬이 되는 사람이 되도록 노력하겠어요.","JPN":"私も1人の騎士として、従者様の役に立つ人になれるよう頑張ります。","ENG":"As a knight myself, I'll try my best to become someone who can support you.","TWN":"但我也會以騎士的身分，努力成為對手下的一臂之力的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};